const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    let bucket = event.Records[0].s3.bucket.name;
    let originalKey = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));

    let params = {
        Bucket: bucket,
        Key: originalKey,
    };

    try {
        let data = await s3.getObject(params).promise();
        let processedData = processData(data.Body);

        let uploadParams = {
            Bucket: 'destination-bucket',
            Key: `processed_${params.Key}`,
            Body: processedData,
        };

        let uploadResult = await s3.putObject(uploadParams).promise();
        return uploadResult;
    } catch (err) {
        console.log(err);
        return err;
    }
}

